import { afterNextRender, AfterViewInit, ChangeDetectorRef, Component, computed, effect, inject, OnDestroy, OnInit, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { DatePipe, AsyncPipe, CommonModule } from '@angular/common';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';
import { ActivatedRoute, Router } from '@angular/router';
import { map, Subscription, switchMap } from 'rxjs';
import { toSignal } from '@angular/core/rxjs-interop';

import {
  AssignedRole,
  AssociationType,
  PRIORITY_LABELS, ROLE_LABELS, StaffUser, STATUS_LABELS,
  TaskDetailView, TaskStatus, TaskSubtaskView, TaskView,
} from '../../../models';
import { TaskService } from '../../../services/task.service';
import { LucideAngularModule } from 'lucide-angular';
import { AuthService } from '../../../services/Base/auth.service';
import { StaffRole } from '../../../shared/guards/permission.service';
import { TutorialService } from '../../../services/tutorial.service';
import { PersonalAppointmentService } from '../../../services/personal-appointment.service';

interface SubtaskFormData {
  name: string;
  priority: number;
  due_date: string;
  task_id: string;
}

interface DetailFormData {
  name: string;
  notes: string;
  due_date: string;
  subtask_id: string;
}

type FormType = 'subtask' | 'detail';
type DeleteType = 'subtask' | 'detail';

@Component({
  selector: 'app-task-detail',
  standalone: true,
  imports: [FormsModule, DatePipe, AsyncPipe, LucideAngularModule, CommonModule],
  templateUrl: './task-detail.component.html',
  styleUrls: ['./task-detail.component.css']
})
export class TaskDetailComponent implements AfterViewInit, OnInit, OnDestroy{
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private taskService = inject(TaskService);
  private sanitizer = inject(DomSanitizer);
  private authService = inject(AuthService);
  private tutorialService = inject(TutorialService);
  private cdr = inject(ChangeDetectorRef);
  public highlightDetailsForSubtaskId = signal<string | null>(null);
  private personalAppointmentService = inject(PersonalAppointmentService);


  // Stato per il form di modifica task
  showTaskForm = signal(false);
  editingTaskId = signal<string | null>(null);
  taskForm = {
    title: '',
    notes: '',
    priority: 3,
    association_type: 'interna' as AssociationType,
    client_name: '',
    assigned_role: 'tutti' as AssignedRole | null,
    assignedRoles: [] as StaffRole[],
    assignedUserIds: [] as string[],
    due_date: '',
    due_time: '',         // ← aggiunto
    due_all_day: false    // ← aggiunto
  };
  staffUsers = signal<StaffUser[]>([]);
  assignToAll = signal<boolean>(false);
  showUsersExpanded = signal<boolean>(false);

  // Reference data per il form (già presenti in TaskListComponent)
  readonly roles = Object.entries(ROLE_LABELS).map(
    ([value, label]) => ({ value: value as AssignedRole, label })
  );
  readonly priorities = [1, 2, 3, 4, 5];

  // Esponiamo loading$ per il template
  loading$ = this.taskService.loading$;

  // Ottieni la task corrente
  task$ = this.route.paramMap.pipe(
    map(params => params.get('id')),
    switchMap(id =>
      this.taskService.tasksView$.pipe(
        map(tasks => tasks.find(t => t.id === id) ?? null)
      )
    )
  );
  task = signal<TaskView | null>(null);
  private taskSubscription!: Subscription;

  // Stato UI
  searchQuery = signal('');
  expandedSubtasks = signal<Set<string>>(new Set());
  showForm = signal(false);
  formType = signal<FormType>('subtask');
  editingId = signal<string | null>(null);
  pendingDelete = signal<{ type: DeleteType; id: string; label: string } | null>(null);
  pendingDeleteTask = signal<{ id: string; title: string } | null>(null); // per eliminazione task
  copyFeedback = signal<string | null>(null);

  // Dati form
  subtaskForm: SubtaskFormData = this.emptySubtaskForm();
  detailForm: DetailFormData = this.emptyDetailForm();

  // Sotto-task e dettagli filtrati
  filteredSubtasks = computed<TaskSubtaskView[]>(() => {
    const q = this.searchQuery().toLowerCase().trim();
    const currentTask = this.task();
    if (!currentTask) return [];
    if (!q) return currentTask.subtasks;
    return currentTask.subtasks.filter(sub =>
      sub.name.toLowerCase().includes(q) ||
      sub.details.some(d =>
        d.name.toLowerCase().includes(q) ||
        (d.notes ?? '').toLowerCase().includes(q)
      )
    );
  });

constructor() {
  effect(() => {
    const currentTask = this.task(); // segnale
    if (currentTask && this.tutorialService.isVisible()) {
      const step = this.tutorialService.currentStepData();
      if (step?.id === 'task-detail') {
        // Ritardo per permettere al DOM di aggiornarsi
        setTimeout(() => this.tutorialService.refreshTooltip(), 100);
      }
    }
  });
  effect(() => {
    const tooltipData = this.tutorialService.currentTooltipData();
    if (tooltipData?.tooltipTarget === '[data-tutorial="task-detail-details"]') {
      const firstId = this.firstSubtaskId();
      if (firstId) {
        // Espandi il primo sotto-task
        this.expandedSubtasks.update(set => set.add(firstId));
        // Imposta l'ID per l'attributo data-tutorial
        this.highlightDetailsForSubtaskId.set(firstId);
      }
    } else {
      // Resetta quando si esce dal sottostep
      this.highlightDetailsForSubtaskId.set(null);
    }
  });
}

  async ngOnInit() {
    const staff = await this.taskService.getStaffUsers();
    this.staffUsers.set(staff);
    
    // Sottoscrivi all'observable per aggiornare il signal
    this.taskSubscription = this.task$.subscribe(task => this.task.set(task));
  }

  ngOnDestroy() {
    this.taskSubscription?.unsubscribe();
  }

  // Label helpers
  statusLabel = (status: string): string => {
    if (Object.keys(STATUS_LABELS).includes(status)) {
      return STATUS_LABELS[status as TaskStatus];
    }
    return status;
  };

  roleLabel = (role: string | null): string => {
    if (!role) return 'Tutti'; // o un'etichetta più appropriata (es. 'Multiplo')
    return ROLE_LABELS[role] ?? role;
  };
  priorityLabel = (priority: number): string => PRIORITY_LABELS[priority] ?? String(priority);

  // Reference data
  readonly statusOptions: { value: TaskStatus; label: string }[] = [
    { value: 'da_iniziare', label: STATUS_LABELS.da_iniziare },
    { value: 'in_lavorazione', label: STATUS_LABELS.in_lavorazione },
    { value: 'completata', label: STATUS_LABELS.completata },
  ];

  // Helper
  isExpanded(id: string): boolean {
    if (this.searchQuery().trim()) return true;
    return this.expandedSubtasks().has(id);
  }

  toggleSubtask(id: string): void {
    const set = new Set(this.expandedSubtasks());
    set.has(id) ? set.delete(id) : set.add(id);
    this.expandedSubtasks.set(set);
  }

  isSubtaskVisible(sub: TaskSubtaskView): boolean {
    const q = this.searchQuery().toLowerCase().trim();
    if (!q) return true;
    return sub.name.toLowerCase().includes(q) ||
      sub.details.some(d =>
        d.name.toLowerCase().includes(q) ||
        (d.notes ?? '').toLowerCase().includes(q)
      );
  }

  isDetailVisible(detail: TaskDetailView): boolean {
    const q = this.searchQuery().toLowerCase().trim();
    if (!q) return true;
    return detail.name.toLowerCase().includes(q) ||
      (detail.notes ?? '').toLowerCase().includes(q);
  }

  highlight(text: string): SafeHtml {
    const q = this.searchQuery().trim();
    if (!q) return text;
    const esc = q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const html = text.replace(
      new RegExp(`(${esc})`, 'gi'),
      '<mark>$1</mark>'
    );
    return this.sanitizer.bypassSecurityTrustHtml(html);
  }

  get formTitle(): string {
    const isEdit = !!this.editingId();
    switch (this.formType()) {
      case 'subtask': return isEdit ? 'Modifica Sotto-task' : 'Nuova Sotto-task';
      case 'detail': return isEdit ? 'Modifica Dettaglio' : 'Nuovo Dettaglio';
    }
  }

  // Apertura form
  openCreateSubtaskForm(event: Event): void {
    event.stopPropagation();
    const currentTask = this.task();
    if (!currentTask) return;
    this.subtaskForm = { ...this.emptySubtaskForm(), task_id: currentTask.id };
    this.editingId.set(null);
    this.formType.set('subtask');
    this.showForm.set(true);
  }

  openEditSubtaskForm(sub: TaskSubtaskView, event: Event): void {
    event.stopPropagation();
    this.subtaskForm = {
      name: sub.name,
      priority: sub.priority,
      due_date: sub.due_date ?? '',
      task_id: sub.task_id,
    };
    this.editingId.set(sub.id);
    this.formType.set('subtask');
    this.showForm.set(true);
  }

  openCreateDetailForm(subtaskId: string, event: Event): void {
    event.stopPropagation();
    this.detailForm = { ...this.emptyDetailForm(), subtask_id: subtaskId };
    this.editingId.set(null);
    this.formType.set('detail');
    this.showForm.set(true);
  }

  openEditDetailForm(detail: TaskDetailView, subtaskId: string, event: Event): void {
    event.stopPropagation();
    this.detailForm = {
      name: detail.name,
      notes: detail.notes ?? '',
      due_date: detail.due_date ?? '',
      subtask_id: subtaskId,
    };
    this.editingId.set(detail.id);
    this.formType.set('detail');
    this.showForm.set(true);
  }

  // Salvataggio
  async saveForm(): Promise<void> {
    switch (this.formType()) {
      case 'subtask': await this.saveSubtask(); break;
      case 'detail': await this.saveDetail(); break;
    }
  }

  private async saveSubtask(): Promise<void> {
    if (!this.subtaskForm.name.trim()) return;
    const payload = {
      name: this.subtaskForm.name.trim(),
      priority: this.subtaskForm.priority,
      due_date: this.subtaskForm.due_date || null,
      task_id: this.subtaskForm.task_id,
    };
    const id = this.editingId();
    id
      ? await this.taskService.updateSubtask(id, payload)
      : await this.taskService.createSubtask(payload);
    this.closeForm();
  }

  private async saveDetail(): Promise<void> {
    if (!this.detailForm.name.trim()) return;
    const payload = {
      name: this.detailForm.name.trim(),
      notes: this.detailForm.notes.trim() || null,
      due_date: this.detailForm.due_date || null,
      subtask_id: this.detailForm.subtask_id,
    };
    const id = this.editingId();
    id
      ? await this.taskService.updateDetail(id, payload)
      : await this.taskService.createDetail(payload);
    this.closeForm();
  }

  closeForm(): void { this.showForm.set(false); }

  // Eliminazione sotto-task / dettagli
  confirmDeleteSubtask(id: string, name: string, event: Event): void {
    event.stopPropagation();
    this.pendingDelete.set({ type: 'subtask', id, label: name });
  }

  confirmDeleteDetail(id: string, name: string, event: Event): void {
    event.stopPropagation();
    this.pendingDelete.set({ type: 'detail', id, label: name });
  }

  cancelDelete(): void { this.pendingDelete.set(null); }

  async executeDelete(): Promise<void> {
    const p = this.pendingDelete();
    if (!p) return;
    if (p.type === 'subtask') await this.taskService.deleteSubtask(p.id);
    if (p.type === 'detail') await this.taskService.deleteDetail(p.id);
    this.pendingDelete.set(null);
  }

  // Eliminazione task
  confirmDeleteTask(id: string, title: string, event: Event): void {
    event.stopPropagation();
    this.pendingDeleteTask.set({ id, title });
  }

  cancelDeleteTask(): void {
    this.pendingDeleteTask.set(null);
  }

  async executeDeleteTask(): Promise<void> {
    const p = this.pendingDeleteTask();
    if (!p) return;
    await this.taskService.delete(p.id);
    this.pendingDeleteTask.set(null);
    this.router.navigate(['/tasks']); // Torna alla lista dopo eliminazione
  }

  // Cambio stato sotto-task (solo se senza dettagli)
  async onSubtaskStatusChange(sub: TaskSubtaskView, status: TaskStatus): Promise<void> {
    await this.taskService.updateSubtask(sub.id, { status });
  }

  // Toggle dettaglio
  async toggleDetail(detail: TaskDetailView): Promise<void> {
    await this.taskService.updateDetail(detail.id, { completed: !detail.completed });
  }

  // Copia task
  async copyTask(task: TaskView, event: Event): Promise<void> {
    event.stopPropagation();
    await navigator.clipboard.writeText(this.taskService.buildTaskCopyText(task));
    this.flashCopy('Task copiata negli appunti ✓');
  }

  // Copia sotto-task
  async copySubtask(sub: TaskSubtaskView, event: Event): Promise<void> {
    event.stopPropagation();
    await navigator.clipboard.writeText(this.taskService.buildSubtaskCopyText(sub));
    this.flashCopy('Sotto-task copiata negli appunti ✓');
  }

  private flashCopy(msg: string): void {
    this.copyFeedback.set(msg);
    setTimeout(() => this.copyFeedback.set(null), 2500);
  }

  // Navigazione indietro
  goBack(): void {
  this.router.navigate(['/restaurant/task-list']);
  }

  // Form vuoti
  private emptySubtaskForm(): SubtaskFormData {
    return { name: '', priority: 3, due_date: '', task_id: '' };
  }
  private emptyDetailForm(): DetailFormData {
    return { name: '', notes: '', due_date: '', subtask_id: '' };
  }

  trackById = (_: number, item: { id: string }) => item.id;

  openEditTaskForm(task: TaskView, event: Event) {
    event.stopPropagation();

    let dueDatePart = '';
    let dueTimePart = '';
    let dueAllDay = task.due_all_day || false;

    if (task.due_date) {
      const date = new Date(task.due_date);
      dueDatePart = date.toISOString().split('T')[0];
      if (!dueAllDay) {
        dueTimePart = date.toTimeString().substring(0, 5);
      }
    }

    this.taskForm = {
      title: task.title,
      notes: task.notes ?? '',
      priority: task.priority,
      association_type: task.association_type,
      client_name: task.client_name ?? '',
      assigned_role: task.assigned_role,
      assignedRoles: task.assignedRoles,
      assignedUserIds: task.assignedUsers.map(u => u.id),
      due_date: dueDatePart,
      due_time: dueTimePart,
      due_all_day: dueAllDay
    };
    this.assignToAll.set(
      task.assigned_role === 'tutti' || 
      (task.assigned_role === null && task.assignedRoles.length === 0 && task.assignedUsers.length === 0)
    );
    this.editingTaskId.set(task.id);
    this.showTaskForm.set(true);
  }

  async saveTask(): Promise<void> {
    if (!this.taskForm.title.trim()) return;

    let dueDatetime = null;
    if (this.taskForm.due_date) {
      const date = this.taskForm.due_date;
      const time = this.taskForm.due_all_day ? '00:00' : (this.taskForm.due_time || '00:00');
      dueDatetime = `${date}T${time}:00`;
    }

    const payload = {
      title: this.taskForm.title.trim(),
      notes: this.taskForm.notes.trim() || null,
      priority: this.taskForm.priority,
      association_type: this.taskForm.association_type,
      client_name: this.taskForm.association_type === 'cliente'
        ? (this.taskForm.client_name.trim() || null)
        : null,
      due_date: dueDatetime,
      due_all_day: this.taskForm.due_all_day
    };
    const id = this.editingTaskId();

    if (this.assignToAll()) {
      if (id) {
        await this.taskService.update(id, { ...payload, assigned_role: 'tutti' });
      } else {
        const newTask = await this.taskService.create({ ...payload, assigned_role: 'tutti' });
        if (newTask) {
          this.router.navigate(['/restaurant/task-detail', newTask.id]);
        }
      }
    } else {
      if (id) {
        await this.taskService.updateTaskWithAssignments(
          id,
          { ...payload, assigned_role: null },
          this.taskForm.assignedRoles,
          this.taskForm.assignedUserIds
        );
      } else {
        const newTask = await this.taskService.createTaskWithAssignments(
          { ...payload, assigned_role: null },
          this.taskForm.assignedRoles,
          this.taskForm.assignedUserIds
        );
        if (newTask) {
          this.router.navigate(['/restaurant/task-detail', newTask.id]);
        }
      }
    }
    this.closeTaskForm();
  }


  closeTaskForm(): void {
    this.showTaskForm.set(false);
    this.editingTaskId.set(null);
  }

  isTaskVisible(task: TaskView): boolean {
    const role = this.authService.getStaffRole();
    const userId = this.authService.currentUserValue?.id;
    const isOwner = this.authService.isOwner();
    const isManager = this.authService.isManager();

    if (isOwner || isManager) return true;
    if (task.assigned_role === 'tutti') return true;

    // Controlla assigned_role singolo
    if (task.assigned_role === role) return true;

    // Controlla array di ruoli (nuovo sistema multi-ruolo)
    if (role && task.assignedRoles?.includes(role as StaffRole)) return true;

    // Controlla assegnazione diretta all'utente
    if (userId && task.assignedUsers?.some(u => u.id === userId)) return true;

    return false;
  }

  toggleRole(role: StaffRole, event: Event) {
    const checked = (event.target as HTMLInputElement).checked;
    if (checked) {
      this.taskForm.assignedRoles = [...this.taskForm.assignedRoles, role];
    } else {
      this.taskForm.assignedRoles = this.taskForm.assignedRoles.filter(r => r !== role);
    }
    if (this.assignToAll()) {
      this.assignToAll.set(false);
    }
  }

  toggleUser(userId: string, event: Event) {
    const checked = (event.target as HTMLInputElement).checked;
    if (checked) {
      this.taskForm.assignedUserIds = [...this.taskForm.assignedUserIds, userId];
    } else {
      this.taskForm.assignedUserIds = this.taskForm.assignedUserIds.filter(id => id !== userId);
    }
    if (this.assignToAll()) {
      this.assignToAll.set(false);
    }
  }


  onAssignToAllChange() {
    if (this.assignToAll()) {
      this.taskForm.assignedRoles = [];
      this.taskForm.assignedUserIds = [];
      this.taskForm.assigned_role = 'tutti';
    } else {
      this.taskForm.assigned_role = null;
    }
  }

openSaveTemplateModal(task: TaskView, event: Event) {
  event.stopPropagation();
  const templateName = prompt('Inserisci un nome per il template:', task.title);
  if (templateName && templateName.trim()) {
    this.taskService.saveAsTemplate(task.id, templateName.trim())
      .then(result => {
        if (result) {
          alert('Template creato con successo!');
        } else {
          alert('Errore durante la creazione del template.');
        }
      });
  }
}

async onTaskStatusChange(status: TaskStatus) {
  const currentTask = this.task();
  if (!currentTask) return;
  await this.taskService.update(currentTask.id, { status });
  // Il task$ si aggiornerà automaticamente grazie al refresh del service
}

  ngAfterViewInit(): void {
    setTimeout(() => {
      if (this.tutorialService.isVisible()) {
        const step = this.tutorialService.currentStepData();
        if (step?.id === 'task-detail') {
          this.tutorialService.refreshTooltip();
        }
      }
    }, 300);
  }

// Calcola l'ID del primo sotto-task (se presente)
private firstSubtaskId = computed(() => {
  const task = this.task();
  return task?.subtasks.length ? task.subtasks[0].id : null;
});

// Metodo per toggle
async toggleCalendarEvent() {
  const task = this.task();
  if (!task) return;

  if (task.calendar_event_id) {
    const confirmed = confirm('Rimuovere questa task dal calendario?');
    if (!confirmed) return;

    const deleted = await this.personalAppointmentService.delete(task.calendar_event_id);
    if (deleted) {
      await this.taskService.update(task.id, { calendar_event_id: null });
      // Aggiorna il segnale locale con tipo esplicito
      this.task.update((current: TaskView | null) => {
        if (!current) return null;
        return { ...current, calendar_event_id: null };
      });
    }
  } else {
    if (!task.due_date) {
      alert('La task non ha una data di scadenza.');
      return;
    }

    const dueDate = new Date(task.due_date);
    let startDate: Date, endDate: Date;
    if (task.due_all_day) {
      startDate = new Date(dueDate);
      startDate.setHours(0, 0, 0, 0);
      endDate = new Date(dueDate);
      endDate.setHours(23, 59, 59, 999);
    } else {
      startDate = dueDate;
      endDate = new Date(dueDate);
      endDate.setHours(dueDate.getHours(), dueDate.getMinutes(), 59, 999);
    }

    const newEvent = await this.personalAppointmentService.create({
      title: `📋 ${task.title}`,
      description: task.notes || '',
      start_datetime: startDate.toISOString(),
      end_datetime: endDate.toISOString(),
      color: '#7209B7',
      is_all_day: task.due_all_day,
      task_id: task.id
    });

    if (newEvent) {
      await this.taskService.update(task.id, { calendar_event_id: newEvent.id });
      this.task.update((current: TaskView | null) => {
        if (!current) return null;
        return { ...current, calendar_event_id: newEvent.id };
      });
    }
  }
}

}